def charge(card, amount):
    for _ in range(3):
        try:
            return http.post('/charge', {'card': card, 'amount': amount}, timeout=5)
        except TimeoutError:
            continue

def load_users(ids):
    users = []
    for uid in ids:
        users.append(http.get(f'/users/{uid}', timeout=2).json())
    return users

def render_page():
    ads = http.get('/ads', timeout=1).json()  # ads service is optional
    return {'ads': ads}
